    34→/* NOTE: all Constant objects belong to the types Token and AST; Constant tokens evaluate to themselves.
    35→ * The variant classes (IntConstant, BoolConstant, EmptyConstant) are defined in the file ValuesTokens.java */
    36→
    37→/** Constant ::= IntConstant | BoolConstant | EmptyConstant */
    38→interface Constant extends Term {}
