    // Handle basic types
    if (t instanceof Variable) {
      String name = ((Variable)t).toString();
      if ("unit".equals(name)) return UnitType.ONLY;
      if ("int".equals(name)) return IntType.ONLY;
      if ("bool".equals(name)) return BoolType.ONLY;
      if ("list".equals(name)) {
