  /** Type checking visitor that validates types and returns the type of each expression. */
  static class TypeCheckVisitor implements ASTVisitor<Type> {
    /** Type environment mapping variables to types */
    private PureList<Variable> vars;
    private PureList<Type> types;

    private TypeCheckVisitor(PureList<Variable> vars, PureList<Type> types) {
      this.vars = vars;
      this.types = types;
    }

    TypeCheckVisitor(PureList<Variable> vars) {
      this(vars, new Empty<Type>());
    }

    /** Look up variable in type environment */
    private Type lookupVar(Variable v) {
      int n = 0;
      PureList<Variable> vList = vars;
      PureList<Type> tList = types;
      while (vList instanceof Cons) {
        Cons<Variable> cVars = (Cons<Variable>) vList;
        Cons<Type> cTypes = (Cons<Type>) tList;
        if (cVars.first() == v) {
          return cTypes.first();
        }
        vList = cVars.rest();
        tList = cTypes.rest();
      }
      return null; // variable not found
    }

    /** Create new TypeCheckVisitor with extended environment */
    private TypeCheckVisitor extend(Variable v, Type t) {
      PureList<Variable> newVars = vars.cons(v);
      PureList<Type> newTypes = types.cons(t);
      return new TypeCheckVisitor(newVars, newTypes);
    }

    public Type forBoolConstant(BoolConstant b) { return BoolType.ONLY; }
    public Type forIntConstant(IntConstant i) { return IntType.ONLY; }
    public Type forEmptyConstant(EmptyConstant n) {
      throw new TypeException("empty must be annotated with a type (e.g., empty: list int)");
    }

    public Type forTypedEmptyConstant(TypedEmptyConstant n) {
      return n.type();
    }

    public Type forVariable(Variable v) {
      Type t = lookupVar(v);
      if (t == null) {
        throw new TypeException("variable " + v + " is unbound");
      }
      return t;
    }

    public Type forPrimFun(PrimFun f) {
      throw new TypeException("primitives cannot be used as values (they must be applied)");
    }

    public Type forUnOpApp(UnOpApp u) {
      Type argType = u.arg().accept(this);
      UnOp op = u.rator();

      if (op == UnOpMinus.ONLY) {
        if (!(argType instanceof IntType)) {
          throw new TypeException("unary - expects int, got " + argType);
        }
        return IntType.ONLY;
      }
      if (op == OpTilde.ONLY) {
        if (!(argType instanceof BoolType)) {
          throw new TypeException("~ expects bool, got " + argType);
        }
        return BoolType.ONLY;
      }
      if (op == OpBang.ONLY) {
        if (!(argType instanceof RefType)) {
          throw new TypeException("! expects ref, got " + argType);
        }
        RefType rt = (RefType) argType;
        return rt.elemType();
      }
      if (op == OpRef.ONLY) {
        return new RefType(argType);
      }
      if (op == UnOpPlus.ONLY) {
        if (!(argType instanceof IntType)) {
          throw new TypeException("unary + expects int, got " + argType);
        }
        return IntType.ONLY;
      }
      throw new TypeException("unknown unary operator: " + op);
    }

    public Type forBinOpApp(BinOpApp b) {
      Type arg1Type = b.arg1().accept(this);
      Type arg2Type = b.arg2().accept(this);
      BinOp op = b.rator();

      if (op == BinOpPlus.ONLY || op == BinOpMinus.ONLY || op == OpTimes.ONLY || op == OpDivide.ONLY) {
        if (!(arg1Type instanceof IntType) || !(arg2Type instanceof IntType)) {
          throw new TypeException(op + " expects int, int but got " + arg1Type + ", " + arg2Type);
        }
        return IntType.ONLY;
      }

      if (op == OpLessThan.ONLY || op == OpGreaterThan.ONLY || op == OpLessThanEquals.ONLY || op == OpGreaterThanEquals.ONLY) {
        if (!(arg1Type instanceof IntType) || !(arg2Type instanceof IntType)) {
          throw new TypeException(op + " expects int, int but got " + arg1Type + ", " + arg2Type);
        }
        return BoolType.ONLY;
      }

      if (op == OpAnd.ONLY || op == OpOr.ONLY) {
        if (!(arg1Type instanceof BoolType) || !(arg2Type instanceof BoolType)) {
          throw new TypeException(op + " expects bool, bool but got " + arg1Type + ", " + arg2Type);
        }
        return BoolType.ONLY;
      }

      if (op == OpEquals.ONLY || op == OpNotEquals.ONLY) {
        // Polymorphic: can compare any two values of the same type
        if (!arg1Type.equals(arg2Type)) {
          throw new TypeException(op + " requires both arguments to have the same type, got " + arg1Type + " and " + arg2Type);
        }
        return BoolType.ONLY;
      }

      if (op == OpGets.ONLY) {
        // ref 'a <- 'a -> unit
        if (!(arg1Type instanceof RefType)) {
          throw new TypeException("<- expects ref, got " + arg1Type);
        }
        RefType rt = (RefType) arg1Type;
        if (!rt.elemType().equals(arg2Type)) {
          throw new TypeException("<- expects ref and value of same type, got " + arg1Type + " and " + arg2Type);
        }
        return UnitType.ONLY;
      }

      throw new TypeException("unknown binary operator: " + op);
    }

    public Type forApp(App a) {
      Type ratorType = a.rator().accept(this);
      AST[] args = a.args();

      // Handle PrimFun applications
      if (a.rator() instanceof PrimFun) {
        PrimFun pf = (PrimFun) a.rator();
        return typeCheckPrimFun(pf, args);
      }

      // Handle function applications
      if (!(ratorType instanceof FunType)) {
        throw new TypeException("function application requires function type, got " + ratorType);
      }

      FunType ft = (FunType) ratorType;
      if (args.length != ft.paramTypes().length) {
        throw new TypeException("function expects " + ft.paramTypes().length + " arguments, got " + args.length);
      }

      for (int i = 0; i < args.length; i++) {
        Type argType = args[i].accept(this);
        if (!argType.equals(ft.paramTypes()[i])) {
          throw new TypeException("argument " + i + " has type " + argType + ", expected " + ft.paramTypes()[i]);
        }
      }

      return ft.resultType();
    }

    /** Type check primitive function applications */
    private Type typeCheckPrimFun(PrimFun pf, AST[] args) {
      if (pf instanceof ConsPrim) {
        if (args.length != 2) {
          throw new TypeException("cons expects 2 arguments, got " + args.length);
        }
        Type arg0 = args[0].accept(this);
        Type arg1 = args[1].accept(this);
        if (!(arg1 instanceof ListType)) {
          throw new TypeException("cons expects (_, list _), got (" + arg0 + ", " + arg1 + ")");
        }
        ListType lt = (ListType) arg1;
        if (!arg0.equals(lt.elemType())) {
          throw new TypeException("cons element types don't match: " + arg0 + " vs " + lt.elemType());
        }
        return arg1;
      }

      if (pf instanceof FirstPrim) {
        if (args.length != 1) {
          throw new TypeException("first expects 1 argument, got " + args.length);
        }
        Type arg = args[0].accept(this);
        if (!(arg instanceof ListType)) {
          throw new TypeException("first expects list, got " + arg);
        }
        return ((ListType) arg).elemType();
      }

      if (pf instanceof RestPrim) {
        if (args.length != 1) {
          throw new TypeException("rest expects 1 argument, got " + args.length);
        }
        Type arg = args[0].accept(this);
        if (!(arg instanceof ListType)) {
          throw new TypeException("rest expects list, got " + arg);
        }
        return arg; // list type
      }

      if (pf instanceof EmptyPPrim) {
        if (args.length != 1) {
          throw new TypeException("empty? expects 1 argument, got " + args.length);
        }
        Type arg = args[0].accept(this);
        if (!(arg instanceof ListType)) {
          throw new TypeException("empty? expects list, got " + arg);
        }
        return BoolType.ONLY;
      }

      if (pf instanceof ConsPPrim) {
        if (args.length != 1) {
          throw new TypeException("cons? expects 1 argument, got " + args.length);
        }
        Type arg = args[0].accept(this);
        if (!(arg instanceof ListType)) {
          throw new TypeException("cons? expects list, got " + arg);
        }
        return BoolType.ONLY;
      }

      // Reject other primitives
      throw new TypeException("primitive " + pf + " cannot be used in typed Jam");
    }

    public Type forMap(Map m) {
      Variable[] vars = m.vars();
      Type[] types = m.types();
      int n = vars.length;

      // Get types from map - if not provided, error
      Type[] paramTypes = new Type[n];
      if (types != null) {
        for (int i = 0; i < n; i++) {
          paramTypes[i] = types[i];
        }
      } else {
        // No types provided, but in typed Jam all map parameters must have types
        throw new TypeException("map parameters must have type annotations");
      }

      // Type check body with extended environment
      TypeCheckVisitor newVisitor = this;
      for (int i = 0; i < n; i++) {
        newVisitor = newVisitor.extend(vars[i], paramTypes[i]);
      }
      Type bodyType = m.body().accept(newVisitor);

      return new FunType(paramTypes, bodyType);
    }

    public Type forIf(If i) {
      Type testType = i.test().accept(this);
      if (!(testType instanceof BoolType)) {
        throw new TypeException("if condition must be bool, got " + testType);
      }

      Type consqType = i.conseq().accept(this);
      Type altType = i.alt().accept(this);

      if (!consqType.equals(altType)) {
        throw new TypeException("if branches have different types: " + consqType + " vs " + altType);
      }

      return consqType;
    }

